from typing import Tuple
from app.models import ReceiptRequest, ReceiptStatus, ObjectStatus


BLOCKED_STATUSES = {ObjectStatus.CANCELLED}
PENDING_REVIEW_STATUSES = {ObjectStatus.DELAYED}

STATUS_REASON_TEMPLATES = {
    ReceiptStatus.PASSED: "对象状态[{status}]在时间窗口内合规，规则版本[{version}]判定通过",
    ReceiptStatus.BLOCKED: "对象状态[{status}]触犯拦截规则，规则版本[{version}]自动拦截",
    ReceiptStatus.PENDING_REVIEW: "对象状态[{status}]需要人工复核，规则版本[{version}]待复核",
}

MAX_TIME_WINDOW_HOURS = 72


def _check_time_window(req: ReceiptRequest) -> Optional[str]:
    delta = req.time_window_end - req.time_window_start
    if delta.total_seconds() <= 0:
        return "时间窗口结束时间必须晚于开始时间"
    if delta.total_seconds() > MAX_TIME_WINDOW_HOURS * 3600:
        return f"时间窗口不得超过{MAX_TIME_WINDOW_HOURS}小时"
    return None


def _check_object_status(status: ObjectStatus) -> Tuple[ReceiptStatus, str]:
    if status in BLOCKED_STATUSES:
        return ReceiptStatus.BLOCKED
    if status in PENDING_REVIEW_STATUSES:
        return ReceiptStatus.PENDING_REVIEW
    return ReceiptStatus.PASSED


def evaluate(req: ReceiptRequest) -> Tuple[ReceiptStatus, str]:
    time_error = _check_time_window(req)
    if time_error:
        return ReceiptStatus.BLOCKED, time_error

    determined_status = _check_object_status(req.object_status)

    reason = STATUS_REASON_TEMPLATES[determined_status].format(
        status=req.object_status.value,
        version=req.rule_version,
    )

    return determined_status, reason


def compute_request_hash(req: ReceiptRequest) -> str:
    raw = f"{req.biz_no}|{req.object_status.value}|{req.time_window_start.isoformat()}|{req.time_window_end.isoformat()}|{req.rule_version}|{req.operator}"
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


