{"content":"from typing import List, Optional
from fastapi import FastAPI, HTTPException, Query
from app.models import (
    ReceiptRequest,
    ReceiptResult,
    BatchReceiptRequest,
    BatchReceiptResponse,
    AuditRecord,
    HistoryEntry,
    ExportRow,
)
from app.service import process_single, get_history, get_audit, export_results

app = FastAPI(
    title="港区拖车任务回执API",
    description="为交通运营人员提供港区拖车任务回执的规则判断、异常解释和处理留痕",
    version="1.0.0",
)


@app.post("/api/v1/receipt", response_model=ReceiptResult, tags=["回执"])
def submit_receipt(req: ReceiptRequest):
    result = process_single(req)
    return result


@app.post("/api/v1/receipt/batch", response_model=BatchReceiptResponse, tags=["回执"])
def submit_batch_receipt(batch: BatchReceiptRequest):
    results: List[ReceiptResult] = []
    errors: List[dict] = []
    for idx, item in enumerate(batch.items):
        try:
            r = process_single(item)
            results.append(r)
        except Exception as exc:
            errors.append({"index": idx, "biz_no": item.biz_no, "error": str(exc)})

    succeeded = sum(
        1 for r in results if r.status not in ("BLOCKED",)
    )
    failed = len(results) - succeeded

    return BatchReceiptResponse(
        total=len(batch.items),
        succeeded=succeeded,
        failed=failed,
        results=results,
        errors=errors,
    )


@app.get("/api/v1/receipt/history/{biz_no}", response_model=List[HistoryEntry], tags=["查询"])
def query_history(biz_no: str):
    history = get_history(biz_no)
    if not history:
        raise HTTPException(status_code=404, detail=f"业务编号 {biz_no} 无历史记录")
    return history


@app.get("/api/v1/receipt/audit/{audit_id}", response_model=AuditRecord, tags=["查询"])
def query_audit(audit_id: str):
    record = get_audit(audit_id)
    if not record:
        raise HTTPException(status_code=404, detail=f"审计记录 {audit_id} 不存在")
    return record


@app.get("/api/v1/receipt/export", response_model=List[ExportRow], tags=["导出"])
def export_receipts(biz_no: Optional[str] = Query(default=None, description="按业务编号过滤")):
    return export_results(biz_no)
